select count(*)
from MEMBER
where ID = #{userId}

select count(*)
from MEMBER
where NICKNAME = #{nickname}

mapper.update:
update MEMBER
set
	NAME = #{name}
	,NICKNAME = #{nickname}
	,PHONE = #{phone}

		,PWD = #{userPwd}

where MEMBER_NO = #{memberNo}

update MEMBER_ROLE
set ROLE_NO = (
	select ROLE_NO
	from ROLE_INFO
	where NAME = 'ROLE_' || #{role}
)
where MEMBER_NO = #{memberNo}
and not exists (
	select 1
	from MEMBER_ROLE MR
	join ROLE_INFO RI on RI.ROLE_NO = MR.ROLE_NO
	where RI.NAME = 'ROLE_SUPER_ADMIN'
	and MR.MEMBER_NO = #{memberNo}
) --최고 관리자 권한 수정 불가

update MEMBER
set STATUS = #{status}
where MEMBER_NO = #{memberNo}
and not exists (
	select 1
	from MEMBER_ROLE MR
	join ROLE_INFO RI on RI.ROLE_NO = MR.ROLE_NO
	where RI.NAME = 'ROLE_SUPER_ADMIN'
	and MR.MEMBER_NO = #{memberNo}
) --최고 관리자 상태 수정 불가

mapper.select:
select count(*)
from MEMBER
where NICKNAME = #{nickname}
and MEMBER_NO != #{memberNo}
